const raw = $input.first()?.json || {};
const execution = raw.execution || {};
const trigger = raw.trigger || {};
const workflow = raw.workflow || {};
const error = execution.error || trigger.error || {};
const cause = error.cause || {};
const text = [error.message, cause.message, error.stack, cause.stack].filter(Boolean).join('\n');
const lower = text.toLowerCase();
const category = /credential|unauthorized|forbidden|401|403|api key|oauth/.test(lower) ? 'Credential/API issue' : /timeout|timed out|rate limit|429/.test(lower) ? 'Timeout/rate limit' : /json|syntax|referenceerror|typeerror|code node/.test(lower) ? 'Code issue' : /missing|required|invalid input|undefined|null|no items/.test(lower) ? 'Data/input issue' : /network|econn|service unavailable|502|503|504/.test(lower) ? 'External service issue' : /node|workflow|branch|connection/.test(lower) ? 'Workflow logic issue' : 'Unknown';
const severity = /credential|unauthorized|forbidden|401|403|out of memory|database|activation/.test(lower) ? 'critical' : /timeout|rate limit|429|service unavailable|502|503|504/.test(lower) ? 'high' : 'medium';
const redact = (value) => {
  const blocked = /password|token|secret|authorization|cookie|api.?key|credential/i;
  const walk = (v, depth = 0) => {
    if (depth > 4) return '[TRUNCATED_DEPTH]';
    if (Array.isArray(v)) return v.slice(0, 10).map(x => walk(x, depth + 1));
    if (v && typeof v === 'object') return Object.fromEntries(Object.entries(v).slice(0, 40).map(([k, x]) => [k, blocked.test(k) ? '[REDACTED]' : walk(x, depth + 1)]));
    if (typeof v === 'string') return v.length > 1000 ? v.slice(0, 1000) + '...[TRUNCATED]' : v;
    return v;
  };
  return walk(value);
};
const failedNode = execution.lastNodeExecuted || error.node?.name || trigger.error?.node?.name || '';
const now = new Date().toISOString();
const fallbackFix = category === 'Credential/API issue' ? 'Verify the affected credential, scopes, and API access.' : category === 'Timeout/rate limit' ? 'Retry with backoff and review timeout or rate-limit handling.' : category === 'Code issue' ? 'Review the failed node code and validate incoming data before parsing.' : category === 'Data/input issue' ? 'Inspect the triggering record and add input validation or defaults.' : category === 'External service issue' ? 'Check service status and add retry/fallback handling.' : 'Inspect the failed execution and upstream node data.';
return [{json:{schema_version:'1.0',id:`jarvis-${Date.now()}-${Math.random().toString(36).slice(2,8)}`,timestamp:now,source_workflow:workflow.name || 'Unknown workflow',workflow_id:workflow.id || '',execution_id:execution.id || '',event_type:'execution_error',status:'failed',severity,failed_node:failedNode,error_message:error.message || cause.message || 'Unknown execution error',error_stack:error.stack || cause.stack || '',ai_diagnosis:`Deterministic fallback classification: ${category}`,diagnosis_category:category,suggested_fix:fallbackFix,urgency:severity === 'critical' ? 'immediate' : severity === 'high' ? 'today' : 'review',business_area:'automation-operations',records_processed:0,summary:`${workflow.name || 'Unknown workflow'} failed${failedNode ? ` at ${failedNode}` : ''}.`,important_outputs_json:'{}',safe_context_json:JSON.stringify(redact(raw.context || error.context || {})),execution_url:execution.url || '',codex_review_recommended:['Code issue','Workflow logic issue','Unknown'].includes(category),resolved_status:'open',expected_frequency:'',last_seen_at:'',minutes_since_last_seen:'',missed_trigger_risk:'',recommended_action:fallbackFix,raw_error_for_ai:text.slice(0,6000)}}];

