const fallback = $('Normalize and Redact Error').first().json;
const current = $input.first()?.json || {};
const ai = current.output || current;
const usable = ai && typeof ai === 'object' && ai.plain_english_diagnosis;
const event = {...fallback};
if (usable) {
  event.diagnosis_category = ai.diagnosis_category || event.diagnosis_category;
  event.ai_diagnosis = `${ai.plain_english_diagnosis}${ai.likely_root_cause ? ` Root cause: ${ai.likely_root_cause}` : ''}`;
  event.suggested_fix = ai.suggested_fix || event.suggested_fix;
  event.urgency = ai.urgency || event.urgency;
  event.codex_review_recommended = Boolean(ai.codex_review_recommended);
  event.recommended_action = ai.suggested_fix || event.recommended_action;
  event.likely_node_or_file = ai.likely_node_or_file || event.failed_node;
} else {
  event.ai_diagnosis = `${event.ai_diagnosis}. AI diagnosis unavailable; fallback retained.`;
  event.likely_node_or_file = event.failed_node;
}
delete event.raw_error_for_ai;
return [{json:event}];

const e = $input.first().json;
const icon = e.severity === 'critical' ? '🚨' : e.severity === 'high' ? '⚠️' : '🛠️';
const execution = e.execution_url ? `<${e.execution_url}|Open failed execution>` : 'Execution link unavailable';
const text = `${icon} *JARVIS SYSTEM ALERT*

*Workflow:* ${e.source_workflow}
*Node:* ${e.failed_node || 'Unknown'}
*Status:* Failed
*Severity:* ${String(e.severity).toUpperCase()}
*Category:* ${e.diagnosis_category}

*Diagnosis:*
${e.ai_diagnosis}

*Suggested Fix:*
${e.suggested_fix}

*Codex Review:* ${e.codex_review_recommended ? 'Recommended' : 'Not currently required'}
*Execution:* ${execution}`;
return [{json:{...e,slack_message:text}}];

const incoming = $input.first()?.json || {};
const body = incoming.body && typeof incoming.body === 'object' ? incoming.body : incoming;
const allowed = ['execution_success','execution_warning','data_processed','slack_message_sent','report_generated','ai_correction_made','manual_review_needed','missed_trigger_detected','workflow_health_check','heartbeat'];
