const valid = Boolean(source && allowed.includes(requestedType));
const eventType = valid ? requestedType : 'execution_warning';
const severity = valid ? (body.severity || (eventType === 'manual_review_needed' || eventType === 'execution_warning' ? 'warning' : 'normal')) : 'warning';
const status = valid ? (body.status || (eventType === 'execution_warning' || eventType === 'manual_review_needed' ? 'warning' : 'success')) : 'rejected';
const now = new Date().toISOString();
