return [{json:event}];

const e = $input.first().json;
const shouldAlert = ['execution_warning','manual_review_needed','missed_trigger_detected'].includes(e.event_type) || ['warning','high','critical'].includes(e.severity);
const icon = e.event_type === 'manual_review_needed' ? '👤' : e.event_type === 'missed_trigger_detected' ? '⏱️' : '⚠️';
