const events = [];
for (const cfg of registry) {
  if (!cfg.expected_minutes) continue;
  const matching = rows.filter(r => String(r.source_workflow || '').toLowerCase().includes(cfg.name.toLowerCase()) || String(r.summary || '').toLowerCase().includes(cfg.name.toLowerCase()));
  const last = matching.sort((a,b) => parse(b.timestamp) - parse(a.timestamp))[0];
