  events.push({json:{schema_version:'1.0',id:`jarvis-health-${Date.now()}-${events.length}`,timestamp:new Date().toISOString(),source_workflow:cfg.name,workflow_id:'',execution_id:'',event_type:'missed_trigger_detected',status:'warning',severity:risk === 'critical' ? 'critical' : 'warning',failed_node:'',error_message:'',error_stack:'',ai_diagnosis:'',diagnosis_category:'Workflow logic issue',suggested_fix:'Verify the workflow is active, inspect its latest execution, and confirm it sends heartbeat pulses.',urgency:risk === 'critical' ? 'immediate' : 'today',business_area:cfg.business_area,records_processed:0,summary,important_outputs_json:'{}',safe_context_json:'{}',execution_url:'',codex_review_recommended:false,resolved_status:'open',expected_frequency:cfg.expected_frequency,last_seen_at:last?.timestamp || '',minutes_since_last_seen:minutes ?? '',missed_trigger_risk:risk,recommended_action:'Verify workflow activation, schedule, credentials, and pulse integration.',slack_message:`⏱️ *JARVIS MISSED TRIGGER ALERT*\n\n*Workflow:* ${cfg.name}\n*Risk:* ${risk.toUpperCase()}\n*Expected:* ${cfg.expected_frequency}\n*Last Seen:* ${last?.timestamp || 'No heartbeat recorded'}\n\n*Recommended Action:* Verify workflow activation, schedule, credentials, and pulse integration.`}});
}
