const rows = $input.all().map(i => i.json);
const tz = 'America/Chicago';
const today = new Date().toLocaleDateString('en-CA',{timeZone:tz});
const dayRows = rows.filter(r => { const d = new Date(r.timestamp || 0); return !Number.isNaN(d.valueOf()) && d.toLocaleDateString('en-CA',{timeZone:tz}) === today; });
const count = type => dayRows.filter(r => r.event_type === type).length;
const failures = dayRows.filter(r => r.status === 'failed' || r.event_type === 'execution_error').length;
