const corrections = count('ai_correction_made');
const missed = count('missed_trigger_detected');
const health = failures > 0 ? Math.max(0,100-failures*15-warnings*5-missed*10) : Math.max(0,100-warnings*5-missed*10);
const text = `🤖 *JARVIS DAILY AUTOMATION PULSE*
_${today} | America/Chicago_

*System Health Score:* ${health}/100
*Workflows Active:* ${workflows.length}
*Successful Events:* ${successes}
*Failed Executions:* ${failures}
*Warnings:* ${warnings}
*Records Processed:* ${records}
*Business Areas Active:* ${areas.length}
*Manual Reviews Needed:* ${manual}
*AI Corrections Made:* ${corrections}
*Missed Trigger Alerts:* ${missed}

*Active Systems:*
${workflows.length ? workflows.slice(0,12).map(w=>`• ${w}`).join('
') : '• No pulse events recorded today'}

Jarvis is monitoring the automation ecosystem.`;
return [{json:{schema_version:'1.0',id:`jarvis-daily-${Date.now()}`,timestamp:new Date().toISOString(),source_workflow:'Jarvis n8n Command Center',workflow_id:'',execution_id:'',event_type:'daily_pulse_summary',status:'success',severity:health < 70 ? 'high' : health < 90 ? 'warning' : 'normal',failed_node:'',error_message:'',error_stack:'',ai_diagnosis:'',diagnosis_category:'',suggested_fix:'',urgency:'low',business_area:'automation-operations',records_processed:records,summary:`Daily pulse: ${successes} successful events, ${failures} failures, ${warnings} warnings, health score ${health}/100.`,important_outputs_json:JSON.stringify({health_score:health,workflows_active:workflows.length,successful_events:successes,failed_executions:failures,warnings,records_processed:records,business_areas_active:areas,manual_reviews_needed:manual,ai_corrections_made:corrections,missed_trigger_alerts:missed}),safe_context_json:'{}',execution_url:'',codex_review_recommended:failures>0,resolved_status:'open',expected_frequency:'daily',last_seen_at:'',minutes_since_last_seen:'',missed_trigger_risk:'',recommended_action:failures>0?'Review today’s failed executions.':'No action required.',slack_message:text}}];
